D=(.5,.866);
draw(circle(O, 1));
dot(O);
draw(A--B--C--D--A--C);
draw(circumcircle(A,B,C));
label("A", A, W);
label("B", B, S);
label("C", C, E);
label("D", D, NE);
label("O", O, N);
label("$r$", (-.4,0), S);
label("$r$", C/2, S);
